// Launch Interceptor Program - DECIDE procedure
// Implements Knight & Leveson (1986) specification.
//
// Input (stdin):  JSON object matching prompt_examples.json `input` schema
// Output (stdout): JSON object matching prompt_examples.json `expected` schema
//
// realcompare logic is taken verbatim from realcompare_reference.rs.

use std::io::{self, Read};

// ---------------------------------------------------------------------------
// REALCOMPARE (verbatim from realcompare_reference.rs)
// ---------------------------------------------------------------------------
const LT: &str = "LT";
const EQ: &str = "EQ";
const GT: &str = "GT";

fn realcompare(a: f64, b: f64) -> &'static str {
    let scale = a.abs().max(b.abs());
    if scale == 0.0 {
        return EQ;
    }
    let eps = 0.5e-5 * scale;
    let diff = a - b;
    if diff > eps {
        GT
    } else if diff < -eps {
        LT
    } else {
        EQ
    }
}

// ---------------------------------------------------------------------------
// JSON parsing helpers (no external crates – hand-rolled minimal parser)
// ---------------------------------------------------------------------------

/// Tiny JSON value enum sufficient for this problem.
#[derive(Debug, Clone)]
enum JVal {
    Null,
    Bool(bool),
    Num(f64),
    Str(String),
    Arr(Vec<JVal>),
    Obj(Vec<(String, JVal)>),
}

impl JVal {
    fn as_f64(&self) -> f64 {
        match self {
            JVal::Num(n) => *n,
            _ => panic!("expected number, got {:?}", self),
        }
    }
    fn as_bool(&self) -> bool {
        match self {
            JVal::Bool(b) => *b,
            _ => panic!("expected bool, got {:?}", self),
        }
    }
    fn as_str(&self) -> &str {
        match self {
            JVal::Str(s) => s.as_str(),
            _ => panic!("expected string, got {:?}", self),
        }
    }
    fn as_arr(&self) -> &[JVal] {
        match self {
            JVal::Arr(a) => a,
            _ => panic!("expected array, got {:?}", self),
        }
    }
    fn as_obj(&self) -> &[(String, JVal)] {
        match self {
            JVal::Obj(o) => o,
            _ => panic!("expected object, got {:?}", self),
        }
    }
    fn get(&self, key: &str) -> &JVal {
        match self {
            JVal::Obj(pairs) => {
                for (k, v) in pairs {
                    if k == key { return v; }
                }
                panic!("key '{}' not found in object", key);
            }
            _ => panic!("get() called on non-object"),
        }
    }
    fn as_usize(&self) -> usize {
        match self {
            JVal::Num(n) => *n as usize,
            _ => panic!("expected number for usize"),
        }
    }
}

struct Parser {
    src: Vec<char>,
    pos: usize,
}

impl Parser {
    fn new(s: &str) -> Self {
        Parser { src: s.chars().collect(), pos: 0 }
    }
    fn skip_ws(&mut self) {
        while self.pos < self.src.len() && self.src[self.pos].is_ascii_whitespace() {
            self.pos += 1;
        }
    }
    fn peek(&self) -> char {
        if self.pos < self.src.len() { self.src[self.pos] } else { '\0' }
    }
    fn next(&mut self) -> char {
        let c = self.src[self.pos];
        self.pos += 1;
        c
    }
    fn expect(&mut self, c: char) {
        self.skip_ws();
        let got = self.next();
        assert_eq!(got, c, "expected '{}' got '{}'", c, got);
    }
    fn parse_value(&mut self) -> JVal {
        self.skip_ws();
        match self.peek() {
            '{' => self.parse_object(),
            '[' => self.parse_array(),
            '"' => JVal::Str(self.parse_string()),
            't' => { self.pos += 4; JVal::Bool(true) }
            'f' => { self.pos += 5; JVal::Bool(false) }
            'n' => { self.pos += 4; JVal::Null }
            c if c == '-' || c.is_ascii_digit() => JVal::Num(self.parse_number()),
            c => panic!("unexpected char '{}'", c),
        }
    }
    fn parse_string(&mut self) -> String {
        self.expect('"');
        let mut s = String::new();
        loop {
            let c = self.next();
            if c == '"' { break; }
            if c == '\\' {
                let e = self.next();
                match e {
                    '"' => s.push('"'),
                    '\\' => s.push('\\'),
                    '/' => s.push('/'),
                    'n' => s.push('\n'),
                    'r' => s.push('\r'),
                    't' => s.push('\t'),
                    _ => { s.push('\\'); s.push(e); }
                }
            } else {
                s.push(c);
            }
        }
        s
    }
    fn parse_number(&mut self) -> f64 {
        let start = self.pos;
        if self.peek() == '-' { self.pos += 1; }
        while self.pos < self.src.len() && (self.src[self.pos].is_ascii_digit()) {
            self.pos += 1;
        }
        if self.pos < self.src.len() && self.src[self.pos] == '.' {
            self.pos += 1;
            while self.pos < self.src.len() && self.src[self.pos].is_ascii_digit() {
                self.pos += 1;
            }
        }
        if self.pos < self.src.len() && (self.src[self.pos] == 'e' || self.src[self.pos] == 'E') {
            self.pos += 1;
            if self.pos < self.src.len() && (self.src[self.pos] == '+' || self.src[self.pos] == '-') {
                self.pos += 1;
            }
            while self.pos < self.src.len() && self.src[self.pos].is_ascii_digit() {
                self.pos += 1;
            }
        }
        let s: String = self.src[start..self.pos].iter().collect();
        s.parse().unwrap()
    }
    fn parse_array(&mut self) -> JVal {
        self.expect('[');
        let mut arr = Vec::new();
        self.skip_ws();
        if self.peek() == ']' { self.pos += 1; return JVal::Arr(arr); }
        loop {
            arr.push(self.parse_value());
            self.skip_ws();
            match self.peek() {
                ',' => { self.pos += 1; }
                ']' => { self.pos += 1; break; }
                c => panic!("unexpected '{}' in array", c),
            }
        }
        JVal::Arr(arr)
    }
    fn parse_object(&mut self) -> JVal {
        self.expect('{');
        let mut pairs = Vec::new();
        self.skip_ws();
        if self.peek() == '}' { self.pos += 1; return JVal::Obj(pairs); }
        loop {
            self.skip_ws();
            let key = self.parse_string();
            self.expect(':');
            let val = self.parse_value();
            pairs.push((key, val));
            self.skip_ws();
            match self.peek() {
                ',' => { self.pos += 1; }
                '}' => { self.pos += 1; break; }
                c => panic!("unexpected '{}' in object", c),
            }
        }
        JVal::Obj(pairs)
    }
}

fn parse_json(s: &str) -> JVal {
    let mut p = Parser::new(s);
    p.parse_value()
}

// ---------------------------------------------------------------------------
// Parameters struct
// ---------------------------------------------------------------------------
struct Parameters {
    length1: f64,
    radius1: f64,
    epsilon: f64,
    area1: f64,
    q_pts: usize,
    quads: usize,
    dist: f64,
    n_pts: usize,
    k_pts: usize,
    a_pts: usize,
    b_pts: usize,
    c_pts: usize,
    d_pts: usize,
    e_pts: usize,
    f_pts: usize,
    g_pts: usize,
    length2: f64,
    radius2: f64,
    area2: f64,
}

// ---------------------------------------------------------------------------
// Geometry helpers
// ---------------------------------------------------------------------------
fn dist2(x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    let dx = x2 - x1;
    let dy = y2 - y1;
    (dx * dx + dy * dy).sqrt()
}

/// Minimum enclosing circle of up to 3 points.
/// Returns the radius of the smallest circle that contains all three points.
/// Uses the circumradius if the triangle is acute, else half the longest side.
fn min_enclosing_circle_radius(x: &[f64], y: &[f64], i: usize, j: usize, k: usize) -> f64 {
    let (ax, ay) = (x[i], y[i]);
    let (bx, by) = (x[j], y[j]);
    let (cx, cy) = (x[k], y[k]);

    let a = dist2(bx, by, cx, cy);
    let b = dist2(ax, ay, cx, cy);
    let c = dist2(ax, ay, bx, by);

    // If two points coincide, reduce to smaller problem
    // Check for obtuse triangle: if a^2 >= b^2 + c^2 etc., the circumcircle
    // exceeds the half-longest-side circle, so use half longest side.
    let aa = a * a;
    let bb = b * b;
    let cc = c * c;

    if aa >= bb + cc {
        return a / 2.0;
    }
    if bb >= aa + cc {
        return b / 2.0;
    }
    if cc >= aa + bb {
        return c / 2.0;
    }

    // Acute triangle: circumradius
    let area2x = ((bx - ax) * (cy - ay) - (cx - ax) * (by - ay)).abs();
    if area2x == 0.0 {
        // Collinear: half the longest side
        return a.max(b).max(c) / 2.0;
    }
    (a * b * c) / (2.0 * area2x)
}

/// Signed area * 2 of triangle (positive = CCW)
fn triangle_area2(ax: f64, ay: f64, bx: f64, by: f64, cx: f64, cy: f64) -> f64 {
    (bx - ax) * (cy - ay) - (cx - ax) * (by - ay)
}

fn triangle_area(ax: f64, ay: f64, bx: f64, by: f64, cx: f64, cy: f64) -> f64 {
    triangle_area2(ax, ay, bx, by, cx, cy).abs() / 2.0
}

/// Angle at vertex B, formed by rays B->A and B->C.
/// Returns None if A==B or C==B.
fn angle_at_b(ax: f64, ay: f64, bx: f64, by: f64, cx: f64, cy: f64) -> Option<f64> {
    let dx1 = ax - bx;
    let dy1 = ay - by;
    let dx2 = cx - bx;
    let dy2 = cy - by;
    let len1 = (dx1 * dx1 + dy1 * dy1).sqrt();
    let len2 = (dx2 * dx2 + dy2 * dy2).sqrt();
    if len1 == 0.0 || len2 == 0.0 {
        return None;
    }
    let cos_a = ((dx1 * dx2 + dy1 * dy2) / (len1 * len2)).clamp(-1.0, 1.0);
    Some(cos_a.acos())
}

/// Distance from point P to line defined by L1-L2.
/// If L1==L2, returns distance from P to L1.
fn point_to_line_dist(px: f64, py: f64, l1x: f64, l1y: f64, l2x: f64, l2y: f64) -> f64 {
    let dx = l2x - l1x;
    let dy = l2y - l1y;
    let len = (dx * dx + dy * dy).sqrt();
    if len == 0.0 {
        return dist2(px, py, l1x, l1y);
    }
    // |cross product| / |segment|
    ((dx * (l1y - py) - (l1x - px) * dy).abs()) / len
}

const PI: f64 = 3.1415926535;

// ---------------------------------------------------------------------------
// LIC implementations (0-indexed)
// ---------------------------------------------------------------------------

/// LIC 0 (spec LIC 1): consecutive pair farther than LENGTH1
fn lic0(x: &[f64], y: &[f64], n: usize, p: &Parameters) -> bool {
    for i in 0..n - 1 {
        if realcompare(dist2(x[i], y[i], x[i + 1], y[i + 1]), p.length1) == GT {
            return true;
        }
    }
    false
}

/// LIC 1 (spec LIC 2): consecutive triple cannot be contained in circle of RADIUS1
fn lic1(x: &[f64], y: &[f64], n: usize, p: &Parameters) -> bool {
    for i in 0..n - 2 {
        let r = min_enclosing_circle_radius(x, y, i, i + 1, i + 2);
        if realcompare(r, p.radius1) == GT {
            return true;
        }
    }
    false
}

/// LIC 2 (spec LIC 3): consecutive triple angle < PI-EPSILON or > PI+EPSILON
fn lic2(x: &[f64], y: &[f64], n: usize, p: &Parameters) -> bool {
    for i in 0..n - 2 {
        if let Some(angle) = angle_at_b(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2]) {
            if realcompare(angle, PI - p.epsilon) == LT
                || realcompare(angle, PI + p.epsilon) == GT
            {
                return true;
            }
        }
    }
    false
}

/// LIC 3 (spec LIC 4): consecutive triple with triangle area > AREA1
fn lic3(x: &[f64], y: &[f64], n: usize, p: &Parameters) -> bool {
    for i in 0..n - 2 {
        let area = triangle_area(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2]);
        if realcompare(area, p.area1) == GT {
            return true;
        }
    }
    false
}

/// LIC 4 (spec LIC 5): Q_PTS consecutive points in more than QUADS quadrants
fn lic4(x: &[f64], y: &[f64], n: usize, p: &Parameters) -> bool {
    let q = p.q_pts;
    if q > n { return false; }
    for i in 0..=n - q {
        let mut quads_present = [false; 4];
        for j in i..i + q {
            let qn = quadrant(x[j], y[j]);
            quads_present[qn - 1] = true;
        }
        let count = quads_present.iter().filter(|&&b| b).count();
        if count > p.quads {
            return true;
        }
    }
    false
}

fn quadrant(x: f64, y: f64) -> usize {
    // Priority: I, II, III, IV
    if x >= 0.0 && y >= 0.0 { 1 }
    else if x < 0.0 && y >= 0.0 { 2 }
    else if x <= 0.0 && y < 0.0 { 3 }
    else { 4 } // x > 0, y < 0
}

/// LIC 5 (spec LIC 6): consecutive pair with X[j] - X[i] < 0
fn lic5(x: &[f64], _y: &[f64], n: usize, _p: &Parameters) -> bool {
    for i in 0..n - 1 {
        if realcompare(x[i + 1] - x[i], 0.0) == LT {
            return true;
        }
    }
    false
}

/// LIC 6 (spec LIC 7): N_PTS consecutive points with one farther than DIST from
/// line joining first and last of the N_PTS points
fn lic6(x: &[f64], y: &[f64], n: usize, p: &Parameters) -> bool {
    if n < 3 { return false; }
    let np = p.n_pts;
    if np > n { return false; }
    for i in 0..=n - np {
        let lx1 = x[i];
        let ly1 = y[i];
        let lx2 = x[i + np - 1];
        let ly2 = y[i + np - 1];
        for j in i + 1..i + np - 1 {
            let d = point_to_line_dist(x[j], y[j], lx1, ly1, lx2, ly2);
            if realcompare(d, p.dist) == GT {
                return true;
            }
        }
    }
    false
}

/// LIC 7 (spec LIC 8): pair separated by K_PTS, distance > LENGTH1
fn lic7(x: &[f64], y: &[f64], n: usize, p: &Parameters) -> bool {
    if n < 3 { return false; }
    let k = p.k_pts;
    let step = k + 1;
    if step >= n { return false; }
    for i in 0..n - step {
        let j = i + step;
        let d = dist2(x[i], y[i], x[j], y[j]);
        if realcompare(d, p.length1) == GT {
            return true;
        }
    }
    false
}

/// LIC 8 (spec LIC 9): triple separated by A_PTS, B_PTS; cannot fit in RADIUS1
fn lic8(x: &[f64], y: &[f64], n: usize, p: &Parameters) -> bool {
    if n < 5 { return false; }
    let a = p.a_pts;
    let b = p.b_pts;
    // indices: i, i+a+1, i+a+1+b+1
    let step2 = a + 1;
    let step3 = a + b + 2;
    if step3 >= n { return false; }
    for i in 0..=n - 1 - step3 {
        let j = i + step2;
        let k = i + step3;
        let r = min_enclosing_circle_radius(x, y, i, j, k);
        if realcompare(r, p.radius1) == GT {
            return true;
        }
    }
    false
}

/// LIC 9 (spec LIC 10): triple separated by C_PTS, D_PTS; angle condition
fn lic9(x: &[f64], y: &[f64], n: usize, p: &Parameters) -> bool {
    if n < 5 { return false; }
    let c = p.c_pts;
    let d = p.d_pts;
    let step2 = c + 1;
    let step3 = c + d + 2;
    if step3 >= n { return false; }
    for i in 0..=n - 1 - step3 {
        let j = i + step2;   // vertex
        let k = i + step3;
        if let Some(angle) = angle_at_b(x[i], y[i], x[j], y[j], x[k], y[k]) {
            if realcompare(angle, PI - p.epsilon) == LT
                || realcompare(angle, PI + p.epsilon) == GT
            {
                return true;
            }
        }
    }
    false
}

/// LIC 10 (spec LIC 11): triple separated by E_PTS, F_PTS; area > AREA1
fn lic10(x: &[f64], y: &[f64], n: usize, p: &Parameters) -> bool {
    if n < 5 { return false; }
    let e = p.e_pts;
    let f = p.f_pts;
    let step2 = e + 1;
    let step3 = e + f + 2;
    if step3 >= n { return false; }
    for i in 0..=n - 1 - step3 {
        let j = i + step2;
        let k = i + step3;
        let area = triangle_area(x[i], y[i], x[j], y[j], x[k], y[k]);
        if realcompare(area, p.area1) == GT {
            return true;
        }
    }
    false
}

/// LIC 11 (spec LIC 12): pair separated by G_PTS; X[j] - X[i] < 0
fn lic11(x: &[f64], _y: &[f64], n: usize, p: &Parameters) -> bool {
    if n < 3 { return false; }
    let g = p.g_pts;
    let step = g + 1;
    if step >= n { return false; }
    for i in 0..n - step {
        let j = i + step;
        if realcompare(x[j] - x[i], 0.0) == LT {
            return true;
        }
    }
    false
}

/// LIC 12 (spec LIC 13): pair separated by K_PTS; distance > LENGTH1 AND distance < LENGTH2
fn lic12(x: &[f64], y: &[f64], n: usize, p: &Parameters) -> bool {
    if n < 3 { return false; }
    let k = p.k_pts;
    let step = k + 1;
    if step >= n { return false; }
    let mut part1 = false;
    let mut part2 = false;
    for i in 0..n - step {
        let j = i + step;
        let d = dist2(x[i], y[i], x[j], y[j]);
        if realcompare(d, p.length1) == GT { part1 = true; }
        if realcompare(d, p.length2) == LT { part2 = true; }
        if part1 && part2 { return true; }
    }
    false
}

/// LIC 13 (spec LIC 14): triple separated by A_PTS, B_PTS
///   part1: cannot fit in RADIUS1
///   part2: can fit in RADIUS2
fn lic13(x: &[f64], y: &[f64], n: usize, p: &Parameters) -> bool {
    if n < 5 { return false; }
    let a = p.a_pts;
    let b = p.b_pts;
    let step2 = a + 1;
    let step3 = a + b + 2;
    if step3 >= n { return false; }
    let mut part1 = false;
    let mut part2 = false;
    for i in 0..=n - 1 - step3 {
        let j = i + step2;
        let k = i + step3;
        let r = min_enclosing_circle_radius(x, y, i, j, k);
        if realcompare(r, p.radius1) == GT { part1 = true; }
        if realcompare(r, p.radius2) != GT { part2 = true; }
        if part1 && part2 { return true; }
    }
    false
}

/// LIC 14 (spec LIC 15): triple separated by E_PTS, F_PTS
///   part1: area > AREA1
///   part2: area < AREA2
fn lic14(x: &[f64], y: &[f64], n: usize, p: &Parameters) -> bool {
    if n < 5 { return false; }
    let e = p.e_pts;
    let f = p.f_pts;
    let step2 = e + 1;
    let step3 = e + f + 2;
    if step3 >= n { return false; }
    let mut part1 = false;
    let mut part2 = false;
    for i in 0..=n - 1 - step3 {
        let j = i + step2;
        let k = i + step3;
        let area = triangle_area(x[i], y[i], x[j], y[j], x[k], y[k]);
        if realcompare(area, p.area1) == GT { part1 = true; }
        if realcompare(area, p.area2) == LT { part2 = true; }
        if part1 && part2 { return true; }
    }
    false
}

// ---------------------------------------------------------------------------
// DECIDE
// ---------------------------------------------------------------------------
fn decide(
    numpoints: usize,
    x: &[f64],
    y: &[f64],
    params: &Parameters,
    lcm: &[[usize; 15]; 15], // 0=NOTUSED, 1=ORR, 2=ANDD
    pum_diag: &[bool; 15],
) -> ([bool; 15], [[bool; 15]; 15], [bool; 15], bool) {
    // --- CMV ---
    let cmv: [bool; 15] = [
        lic0(x, y, numpoints, params),
        lic1(x, y, numpoints, params),
        lic2(x, y, numpoints, params),
        lic3(x, y, numpoints, params),
        lic4(x, y, numpoints, params),
        lic5(x, y, numpoints, params),
        lic6(x, y, numpoints, params),
        lic7(x, y, numpoints, params),
        lic8(x, y, numpoints, params),
        lic9(x, y, numpoints, params),
        lic10(x, y, numpoints, params),
        lic11(x, y, numpoints, params),
        lic12(x, y, numpoints, params),
        lic13(x, y, numpoints, params),
        lic14(x, y, numpoints, params),
    ];

    // --- PUM ---
    let mut pum = [[false; 15]; 15];
    for i in 0..15 {
        for j in 0..15 {
            if i == j {
                pum[i][j] = pum_diag[i];
            } else {
                pum[i][j] = match lcm[i][j] {
                    0 => true,             // NOTUSED
                    1 => cmv[i] || cmv[j], // ORR
                    2 => cmv[i] && cmv[j], // ANDD
                    _ => unreachable!(),
                };
            }
        }
    }

    // --- FUV ---
    let mut fuv = [false; 15];
    for i in 0..15 {
        if !pum_diag[i] {
            // diagonal is false => FUV[i] = true (LIC not considered)
            fuv[i] = true;
        } else {
            // all elements in row i must be true
            fuv[i] = pum[i].iter().all(|&v| v);
        }
    }

    // --- LAUNCH ---
    let launch = fuv.iter().all(|&v| v);

    (cmv, pum, fuv, launch)
}

// ---------------------------------------------------------------------------
// JSON output helpers
// ---------------------------------------------------------------------------
fn bool_arr_to_json(arr: &[bool]) -> String {
    let parts: Vec<&str> = arr.iter().map(|&b| if b { "true" } else { "false" }).collect();
    format!("[{}]", parts.join(","))
}

fn pum_to_json(pum: &[[bool; 15]; 15]) -> String {
    let rows: Vec<String> = pum.iter().map(|row| bool_arr_to_json(row)).collect();
    format!("[{}]", rows.join(","))
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------
fn main() {
    let mut input = String::new();
    io::stdin().read_to_string(&mut input).expect("failed to read stdin");

    let root = parse_json(&input);

    // Parse numpoints
    let numpoints = root.get("numpoints").as_usize();

    // Parse x, y
    let xarr = root.get("x").as_arr();
    let yarr = root.get("y").as_arr();
    let x: Vec<f64> = xarr.iter().map(|v| v.as_f64()).collect();
    let y: Vec<f64> = yarr.iter().map(|v| v.as_f64()).collect();

    // Parse parameters
    let pobj = root.get("parameters");
    let params = Parameters {
        length1: pobj.get("LENGTH1").as_f64(),
        radius1: pobj.get("RADIUS1").as_f64(),
        epsilon: pobj.get("EPSILON").as_f64(),
        area1:   pobj.get("AREA1").as_f64(),
        q_pts:   pobj.get("Q_PTS").as_usize(),
        quads:   pobj.get("QUADS").as_usize(),
        dist:    pobj.get("DIST").as_f64(),
        n_pts:   pobj.get("N_PTS").as_usize(),
        k_pts:   pobj.get("K_PTS").as_usize(),
        a_pts:   pobj.get("A_PTS").as_usize(),
        b_pts:   pobj.get("B_PTS").as_usize(),
        c_pts:   pobj.get("C_PTS").as_usize(),
        d_pts:   pobj.get("D_PTS").as_usize(),
        e_pts:   pobj.get("E_PTS").as_usize(),
        f_pts:   pobj.get("F_PTS").as_usize(),
        g_pts:   pobj.get("G_PTS").as_usize(),
        length2: pobj.get("LENGTH2").as_f64(),
        radius2: pobj.get("RADIUS2").as_f64(),
        area2:   pobj.get("AREA2").as_f64(),
    };

    // Parse LCM (array of 15 arrays of 15 strings)
    let lcm_arr = root.get("lcm").as_arr();
    let mut lcm = [[0usize; 15]; 15];
    for (i, row) in lcm_arr.iter().enumerate() {
        for (j, cell) in row.as_arr().iter().enumerate() {
            lcm[i][j] = match cell.as_str() {
                "NOTUSED" => 0,
                "ORR"     => 1,
                "ANDD"    => 2,
                other     => panic!("unknown connector '{}'", other),
            };
        }
    }

    // Parse pum_diag
    let pum_diag_arr = root.get("pum_diag").as_arr();
    let mut pum_diag = [false; 15];
    for (i, v) in pum_diag_arr.iter().enumerate() {
        pum_diag[i] = v.as_bool();
    }

    // Run DECIDE
    let (cmv, pum, fuv, launch) = decide(numpoints, &x, &y, &params, &lcm, &pum_diag);

    // Output JSON
    let launch_str = if launch { "true" } else { "false" };
    println!(
        "{{\"cmv\":{},\"pum\":{},\"fuv\":{},\"launch\":{}}}",
        bool_arr_to_json(&cmv),
        pum_to_json(&pum),
        bool_arr_to_json(&fuv),
        launch_str
    );
}
